                            "code": "# === JUNIOR EXAMPLE ===\n# TASK      - Real-world usage of OpenAI Chat Completions — GPT-4, Structured Output & Streaming — common patterns you'll see in production.\n# APPROACH  - Combine OpenAI Chat Completions — GPT-4, Structured Output & Streaming with related functions; handle common edge cases.\n# STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n# WEAKNESSES- May need optimization for large datasets or complex scenarios.\nimport asyncio\nfrom openai import AsyncOpenAI, OpenAI\nfrom pydantic import BaseModel\n# 1) Structured output -- Pydantic schema is the contract.\nclass Review(BaseModel):\n    severity: str          # \"low\" | \"medium\" | \"high\"\n    issues: list[str]\n    fix: str\nclient = OpenAI()\nresp = client.beta.chat.completions.parse(\n    model=\"gpt-4o-mini\",\n    messages=[\n        {\"role\": \"system\", \"content\": \"Code reviewer. Return strict JSON.\"},\n        {\"role\": \"user\",   \"content\": \"def add(a, b): return a + b\"},\n    ],\n    response_format=Review,\n)\nr: Review = resp.choices[0].message.parsed\nprint(r.severity, r.issues)\n# 2) Streaming -- show tokens as they arrive.\ndef stream_answer(prompt: str) -> str:\n    chunks: list[str] = []\n    for ev in client.chat.completions.create(\n        model=\"gpt-4o-mini\",\n        messages=[{\"role\": \"user\", \"content\": prompt}],\n        stream=True,\n    ):\n        delta = ev.choices[0].delta.content\n        if delta:\n            chunks.append(delta); print(delta, end=\"\", flush=True)\n    return \"\".join(chunks)\n# 3) Async client for FastAPI / aiohttp servers.\nasync_client = AsyncOpenAI()\nasync def ask(prompt: str) -> str:\n    r = await async_client.chat.completions.create(\n        model=\"gpt-4o-mini\",\n        messages=[{\"role\": \"user\", \"content\": prompt}],\n    )\n    return r.choices[0].message.content"
