                            "code": "# === ENTRY-LEVEL EXAMPLE ===\n# TASK      - Basic usage of Fine-Tuning LLMs — When & How — understand the core syntax and behavior.\n# APPROACH  - Simple example with minimal parameters; no edge cases.\n# STRENGTHS - Clear, readable; shows the fundamental pattern.\n# WEAKNESSES- Not production-ready; no error handling or complex scenarios.\nimport json\nfrom openai import OpenAI\nclient = OpenAI()\n# 1) Build training data: at least ~50 examples for any signal.\ndata = [\n    {\"messages\": [\n        {\"role\": \"system\",    \"content\": \"Generate Postgres SQL only.\"},\n        {\"role\": \"user\",      \"content\": \"Users who signed up last month\"},\n        {\"role\": \"assistant\", \"content\":\n         \"SELECT * FROM users WHERE created_at >= now() - interval '1 month'\"},\n    ]},\n    # ... many more\n]\n# 2) Save as JSONL.\nwith open(\"train.jsonl\", \"w\") as f:\n    for ex in data:\n        f.write(json.dumps(ex) + \"\\n\")\n# 3) Upload + train.\nfid  = client.files.create(file=open(\"train.jsonl\",\"rb\"), purpose=\"fine-tune\").id\njob  = client.fine_tuning.jobs.create(training_file=fid, model=\"gpt-4o-mini-2024-07-18\")\nprint(job.id)"
